// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Propiedad) predicate.Propiedad {
	return predicate.Propiedad(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Propiedad) predicate.Propiedad {
	return predicate.Propiedad(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Propiedad) predicate.Propiedad {
	return predicate.Propiedad(sql.NotPredicates(p))
}
